import{_ as b,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const h=JSON.parse('{"title":"1.人机改-器官","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/4.综合类/人机改/1.人机改-器官.md","filePath":"4.资源分区/2.改造与功法/改造/4.综合类/人机改/1.人机改-器官.md"}'),s={name:"4.资源分区/2.改造与功法/改造/4.综合类/人机改/1.人机改-器官.md"};function _(o,p,d,l,i,I){return e(),a("div",null,[...p[0]||(p[0]=[r("h1",{id:"_1-人机改-器官",tabindex:"-1"},[t("1.人机改-器官 "),r("a",{class:"header-anchor",href:"#_1-人机改-器官","aria-label":'Permalink to "1.人机改-器官"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风023元旦版")])])],-1),n('<h1 id="_1-人机改-器官-1" tabindex="-1">1.人机改-器官 <a class="header-anchor" href="#_1-人机改-器官-1" aria-label="Permalink to &quot;1.人机改-器官&quot;">​</a></h1><p>器官<br> 器官-眼部</p><p>真视I型光学增强眼球<br> D+500/1对<br> 市面上流通的大路货，没什么特点，但有时能救你一命。<br> 这对眼球将代替使用者的原生眼球，无法非成对替换。真视I型光学增强眼球将为使用者提供【黑暗视觉】和临时骇入能力。<br> 临时骇入：一轮一次，可以使用智力-器用-计算机操作的检定对抗一个在你视距范围的目标的伪装检定，若检定成功，则立即对其解析一次，这是一个C级科技本质的解析效果，仍需遵循解析的基本效果。</p><p>真视II型狙击手特用眼球<br> C+1000/1对<br> 军方为重点培养的士兵所提供的优质义眼，同样来自幻啸公司，动态跟踪和抗干扰能力一流。<br> 这对眼球将代替使用者的原生眼球，无法非成对替换。真视II型狙击手特用眼球将为使用者提供在射击检定时无视2点环境减值的效果，使用者的视距将提升一倍，并获得D级科技本质的侦测效果。</p><p>静谧I型破译增强眼球<br> D+500/1只<br> 初级骇客经常会选择的一款义眼，但因其占用电力过高，而很快就会在赚钱后取出卖掉，这种义眼在黑市交易网上很常见。<br> 这颗眼球将代替使用者的原生眼球，可以非成对替换。静谧I型破译增强眼球将额外占据6点电力上限，这只眼球的使用者在进行一次器用检定时需额外支付3点电力，那次检定将额外获得算力4。<br> 算力X：只要那次器用检定的成功数不为0，则可以直接通过DC小于等于X的侦查检定，若触发了算力X但未直接通过，则改为获得X点那次检定上的附加成功。</p><p>静谧II型骇客特用眼球<br> B+2000/1只<br> 更抢手，也更缺货的好东西，相比于要消耗大量电力的静谧I型，静谧II型骇客特用眼球是完全为骇客这一群体量身打造的义眼，不但可以掩盖踪迹，还可以更好的辅助骇入。</p><p>这颗眼球将代替使用者的原生眼球，可以非成对替换。静谧II型骇客特用眼球具有内置互联能力，可以让使用者在任何情况下都能正常无介质接入网络，除非本世界没有网络，这是一个无支线信息来源的效果。在接入网络时，使用者始终视为在网络上具有C级科技本质的反侦测效果，并提供深度骇入能力。<br> 深度骇入：一轮一次，可以使用智力-器用-计算机操作的检定对抗一个在你视距范围的目标或网络中能够获取其IP的目标的伪装检定，此次检定额外需支付1点意志，并获得算力4，若检定成功，则立即对其解析一次，这是一个B级科技本质的解析效果，仍需遵循解析的基本效果。</p><p>恐惧I型激光眼<br> D+500/1对<br> 如果说有什么稀奇古怪的发明，那么激光眼义体一定可以排得上号，其运作方式就是在眼部聚集大量能量，并射出一道激光，战斗力不一定怎么样，但确实能唬住人。<br> 这对眼球将代替使用者的原生眼球，无法非成对替换。使用恐惧I型激光眼攻击需消耗1点电力，并将为使用者提供24+2DP的预设检定，具有高速5和熔毁2。</p><p>器官-脑部</p><p>均衡I型电子脑<br> D+500<br> 适合新手使用的均衡算力电子脑，在受击抵抗方面也称得上合格，能够协调肢体和动作的配合。<br> 这颗大脑将代替使用者的原生大脑。均衡I型电子脑会为使用者提供【谐振】和【稳固】，并提供1点算力。<br> 稳固：受到头部部位攻击时，将部位攻击附带的额外晕眩点数从每3点转化为每4点附带1点。</p><p>“极化”实验原型体<br> C+1000<br> 不知道哪个不怕死的把极化系列的原型体外流到了黑市上，虽然其功率大的惊人，但这颗电子脑的技术太过于不稳定，可能会给使用者带来各种意想不到的麻烦和永久性伤害，但其的仿制品还是被源源不断的制出，卖给那些打定主意要只再活几个月甚至几周的亡命之徒。<br> 这颗大脑将代替使用者的原生大脑。“极化”实验原型体将给予使用者一种新的检定增幅方式，每轮一次，在器用检定时，可以选择1项自身具有的属性，令其永久下降1点，并在这次检定中获得3点额外的算力，此外，“极化”实验原型体还会提供【狂怒6】，每次使用“极化”实验原型体提供的检定增幅方式，就需承受1点不可豁免的剧痛点数，以此法获得的剧痛点数每具有1点，在本轮内就会将狂怒额外提升1点。</p><p>“极化”稳定型电子脑<br> C+1000<br> 在实验原型体意外流入市场后，幻啸集团也仓促发布了“极化”稳定型，原本狂暴输出功率的部分实际上原本的设计是用于集成算力，以增强自身，但看起来这种需要算力支持的电子脑并没有实验原型体受欢迎，反将了正版货一军。<br> 这颗大脑将代替使用者的原生大脑。“极化”稳定型电子脑根据使用者的常态算力而提供如下效果：<br> 3点算力：只要电力池不空，使用者就始终具有基于护甲防御的【防能量】效果。<br> 5点算力：在进行招架时，可以将使用者具有的每1点算力转换为2点护甲防御。<br> 8点算力：每轮一次，在一次使用了算力的检定中，使用者可以选择重掷那次检定结果，但必须接受后者的出目。<br> 11点算力：使用者获得基于护甲防御的【超级坚韧】效果。</p><p>矿工专用型电子脑<br> D+500<br> 这种电子脑是专门为矿工准备的挖矿型，通过占据算力而挖出货币，但代价是会占用大量电力，且挖矿速度并不高，可以用效率低下来形容。<br> 这颗大脑将代替使用者的原生大脑。矿工专用型电子脑将为使用者提供【低效挖矿】和2点算力。<br> 低效挖矿：一场影片一次，在影片中消耗3点电力，开始为期一场景的挖矿，在这个场景结束时，将立即获得该影片世界观下的价值250分的货币，若在影片结束时未完全花光，则视为自动失去。</p><p>》》》》》》》》》<br> “缪斯”特化模块V2<br> D+500</p><p>你对音乐的渴望和执着已经超越了一般人，这让你愿意在大脑中植入此模块让你成为一名特殊的音乐人。植入此模块后，音乐的知识涌入你的脑海，你可以选择性的摄入特定方面的知识，可以指定一种乐器，演奏指定种类的乐器时，可以用专业：唱歌相关检定代替；或者，如果你原本就擅长某种乐器，可以用指定乐器的专业相关检定代替唱歌专业进行唱歌相关检定。当然，你也可以不选，改为表达相关检定获得1附加成功。</p><p>“缪斯”系列模块自带内存芯片，你可以将你在脑海中生成的歌曲储存在芯片中，随时可以修改，每次作曲需要消耗一天时间，一次专业：唱歌或专业：任意乐器相关的检定决定了成品歌曲的品质。作曲完成后，你可以随时通过你自己的口舌或乐器演奏，如果你身在一个有着网络的世界，你还可以通过数据线接入网络上传歌曲甚至直播演唱。<br> 听到歌曲的人，需要使用意志豁免同你创作歌曲时的成功数进行对抗，对抗失败会成为你的粉丝，你可以让他帮忙安利你的曲子或者帮你做一些无伤大雅的事情，例如帮你买水之类的，视为受到影响心灵来源的D级思维控制的效果。 你的歌曲受到思维控制的单位视为受到了来源为你的模因影响，但由于模块性能的限制，你的成品曲目可能无法很好的表达你的真意，并且存在混音的问题，因此似乎无法掀起太大波澜，受到影响的人并没有太多安利给亲友的意愿，如果没有你的指示，仅仅是见到好友的时候顺嘴安利一下，因为音质的问题，效果甚微，至少一个月你才会获得一两个粉丝，这视为信息来源的D级模因效果。</p><p>注意：下文提及的所有【歌曲附带的思维控制】仅能通过发布乐曲和演唱/演奏已发布乐曲使目标获得，视为受到模因影响，成为传播模因的媒介之一。模因的效果仅在战斗外生效，毕竟没人能在战斗的同时回消息吧。</p><p>“缪斯”特化模块V3<br> C+1000<br> （需要由“缪斯”特化模块V2升级）</p><p>随着模块的升级，你获得了更多的知识，这让你的唱歌相关检定或者某种乐器演奏相关检定获得9加骰。这个版本带给你的不只是这样，还让你更适应现场表演，在战斗中你演奏已发布曲目时可以将攻击范围转化成半径等同于1/2射程的圆形范围。</p><p>随着性能的升级，你创作的曲子质量上升，同时能也更好的表达你的情感，但混音还是有点渣，虽然没有为传播带来帮助，但你的作曲技术在不断上升，你的曲子还是为你带来了一小部分粉丝，可以让他们为你做些事，例如成立粉丝俱乐部、制作宣传网站、策划演唱会等，但因为你的粉丝还不至于狂热，无法让他们做伤天害理的事。尽管你的曲子依旧很难掀起波澜，但至少比之前好了，你的粉丝们会向亲友们安利你的曲子，但往往会因为渣混音被劝退，粉丝数量上涨趋势得按周计算，但至少比之前好些了。 现在你在网上发布的歌曲会以较快的速度传播，其速率大致为每日传播数百人，听闻歌曲的单位往往会不自觉的将这部分歌曲进行转发操作，这视为信息来源的模因等级升级为C级。</p><p>“缪斯”特化模块V4<br> B+2000<br> （需要由“缪斯”特化模块V3升级）</p><p>随着模块再一次升级，你对音乐的造诣更上一层楼，在上一级获得的加骰升级为8加骰，你的歌曲能够更大限度的打动更多的人。在战斗中，你的唱歌相关检定或者某种乐器演奏相关检定获的加骰上升一级，至多为8加骰，每轮一次，如果对音乐相关的表达检定不满意，可以重投一次，取其中最高的一次进行结算。</p><p>你的曲子在摆脱渣混音后更受欢迎，你的粉丝们会把你的曲子转发到社交圈里，甚至还会为你在互联网上冲锋，你甚至可以指示粉丝们在网络上带节奏、实施网络暴力（当然他们会不会干是另一回事）。 你的曲子快速在一片地区或某个受众团体中扩散，粉丝数量以日为单位上涨，每天新增两位数甚至三位数的粉丝量让你开心。 现在你在网上发布的歌曲会以极快的速度传播，你的歌曲在电子物品上播放后，会随机的通过电磁波传播给周围的其他电子物品，这会令你的歌曲在数日内传播给一整座城市这视为信息来源的模因效果升级为B级。</p><p>“缪斯”特化模块V5<br> A+4000<br> （需要由“缪斯”特化模块V4升级）</p><p>这次升级让你的性能更加优秀，你的声音更加嘹亮，你对音乐抱有更大的热情，没有人能阻止你的歌唱，你免疫S级及以下沉默。在战斗中，你对音乐直击灵魂，你使用音乐相关检定的攻击带有影响心灵来源的扼魂特性，每轮一次使用表达相关检定的检定成功数增加一半。</p><p>你创作的曲目有一相当一部分被称为神曲，你的粉丝群体几乎成为了一个把你当作神明的宗教团体。因为你的曲子质量过硬，不少创作者会使用你的曲子作为BGM制作二创和meme，你的曲子因此火爆出圈，这为你带来了更多、更疯狂的粉丝，每时每刻都有成千上万人成为你的粉丝。你的粉丝团体因为人数众多变得饭圈化、不理智，这对你来说可能不算坏事，至少就算你塌房了还是会有人护着你。 现在你的歌曲在发布后，会在网络上不受控制的被各网站、设备、甚至于卫星通讯莫名其妙的散播开来，其大致速度足以在一周内覆盖整个国家范围的电子产品，这视为信息来源的模因升级为A级。 》》》》》》》》》</p><p>器官-其他</p><p>幻啸-备用心脏<br> C+1000<br> 幻啸-备用心脏是幻啸集团的拳头产品之一，可以替代心脏进行工作，也可以轮替工作，更可以与原生心脏同时工作以加速循环。<br> 这颗心脏将不会替换使用者的原生心脏。备用心脏将为使用者提供2点仅能用于治疗疲乏点数的异常点治疗（24医疗点），且使用者的疲乏周期加长一个周期，同时，备用心脏将会自动储存能够修补身体和状态的修补液，且通过人体循环自动制造修补液，每植入备用心脏经过一场影片，就会自动制造4份修补液，当使用者受到属性伤害或属性因某种原因而降低时，可以选择消耗任意份拥有的修补液，抵销等量的属性伤害或属性降低。</p><p>均衡I型仿生肺<br> 500<br> 这是一套能够在任何环境正常使用的仿生肺，也可以延长使用者的免呼吸时间。<br> 这套仿生肺系统将会替换使用者的原生呼吸系统。均衡I型仿生肺将提供全环境呼吸能力，以及延长一倍的闭气时间。</p><p>军用扩展机械耳蜗<br> C+1000<br> 这是一套军方用于增强听力，帮助更好地适应战场环境的机械耳蜗，且可以有效解决包括过度紧张导致的耳鸣在内的大部分听力生理和心理问题。<br> 这套军用扩展机械耳蜗系统将会替换使用者的原生听力系统。军用扩展机械耳蜗将提供免疫B级耳聋的效果，并为使用者提供基于听力的C级科技本质强感知侦测方式，听力范围将扩大一倍。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',32)])])}const D=b(s,[["render",_]]);export{h as __pageData,D as default};
